-- HostApp application schema (Auth-first refactor)
-- This script is executed automatically by the database container on first boot.
-- It defines only HostApp-owned tables (authorization lives in Authentik).
--
-- NOTE: SQLAlchemy-Continuum audit trail tables (`transaction`, `tenants_version`,
-- `users_version`) are auto-generated by the ORM at startup via Base.metadata.create_all()
-- and are NOT defined here. For production environments using Alembic, those tables are
-- managed by Alembic migrations instead.

CREATE TABLE IF NOT EXISTS tenants (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL UNIQUE,
    default_language TEXT DEFAULT 'en',
    logo BYTEA NULL
);

CREATE TABLE IF NOT EXISTS users (
    id SERIAL PRIMARY KEY,
    username TEXT NOT NULL UNIQUE,
    email TEXT UNIQUE,
    full_name TEXT,
    first_name TEXT,
    last_name TEXT,
    telephone TEXT,
    authentik_internal_id TEXT UNIQUE,
    tenant_fk INTEGER REFERENCES tenants(id) ON DELETE SET NULL,
    default_language TEXT,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_superadmin BOOLEAN NOT NULL DEFAULT FALSE
);

CREATE INDEX IF NOT EXISTS idx_users_tenant_fk ON users(tenant_fk);

-- Dedicated audit table for tenant-user associations.
-- One row per associate/disassociate operation so rapid successive changes
-- are never collapsed or lost.
CREATE TABLE IF NOT EXISTS user_tenant_audit (
    id SERIAL PRIMARY KEY,
    user_fk INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    tenant_fk INTEGER NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    operation_type INTEGER NOT NULL, -- 3 = ASSOCIATE, 4 = DISASSOCIATE
    actor TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_user_tenant_audit_user ON user_tenant_audit(user_fk);
CREATE INDEX IF NOT EXISTS idx_user_tenant_audit_tenant ON user_tenant_audit(tenant_fk);
CREATE INDEX IF NOT EXISTS idx_user_tenant_audit_created_at ON user_tenant_audit(created_at);

-- Stable UUID -> integer ID mapping for Authentik-backed entities.
-- Replaces the ephemeral /tmp/hostapp_auth_entity_ids.json file.
CREATE TABLE IF NOT EXISTS auth_entity_mapping (
    id SERIAL PRIMARY KEY,
    entity_type TEXT NOT NULL,
    authentik_uuid TEXT NOT NULL,
    local_id INTEGER NOT NULL,
    UNIQUE (entity_type, authentik_uuid)
);

CREATE INDEX IF NOT EXISTS idx_auth_entity_mapping_type_uuid ON auth_entity_mapping(entity_type, authentik_uuid);
CREATE INDEX IF NOT EXISTS idx_auth_entity_mapping_local_id ON auth_entity_mapping(entity_type, local_id);
